module top_module(
    clk,
    in,
    load,
    address,
    out
 );input clk;             
    input [15:0] in;       
    input load;            
    input [15:0] address;  
    output [15:0] out;            

    reg [15:0] ram[0:24000]; 
    reg [15:0]value; 

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk  or posedge dbg_halt) begin
        if (load) begin
            ram[address] <= in;
        end else begin
            value <= ram[address];
        end
    end

    assign out = value;

endmodule
